{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  /* HEADER */
  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  /* PILLS */
  .pill { display: inline-block; padding: 2px 9px; border-radius: 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; margin-right: 5px; border: 1px solid #d1d5db; background: #f9fafb; color: #374151; }
  .pills-row { margin-bottom: 12px; }

  /* SECTION TITLE */
  .section-title { font-size: 7.5pt; font-weight: 700; color: #fff; text-transform: uppercase; letter-spacing: 0.6px; background: #1a1a2e; padding: 6px 9px; margin-top: 12px; margin-bottom: 8px; }

  /* INFO TABLE */
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 16%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 17%; color: #1a1a2e; font-weight: 400; }

  /* STATS */
  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }

  /* PREFERENCE TABLE */
  .pref-table { width: 100%; border-collapse: collapse; table-layout: fixed; }
  .pref-table thead tr { background: #1a1a2e; color: #fff; }
  .pref-table thead th { padding: 5px 6px; font-size: 7pt; font-weight: 700; text-align: left; border: 1px solid #374151; text-transform: uppercase; letter-spacing: 0.3px; }
  .pref-table thead th.staff-col { width: 14%; }
  .pref-table thead th.status-col { width: 7%; }
  .pref-table tbody td { padding: 4px 5px; font-size: 8pt; border: 1px solid #e5e7eb; vertical-align: top; }
  .pref-table tbody td.staff-col { background: #f9fafb; }
  .pref-table tbody td.staff-col .s-name { font-weight: 700; color: #1a1a2e; }
  .pref-table tbody td.staff-col .s-role { font-size: 6.5pt; color: #9ca3af; margin-top: 1px; }
  .pref-table tbody tr:nth-child(even) td:not(.staff-col) { background: #fcfcfd; }

  /* PREFERENCE PILLS */
  .pref-pill { border-radius: 4px; padding: 3px 4px; font-weight: 700; font-size: 7.5pt; text-align: center; display: block; }
  .morning     { background: #dbeafe; color: #1e40af; }
  .afternoon   { background: #fef3c7; color: #92400e; }
  .night       { background: #e0e7ff; color: #3730a3; }
  .unavailable { background: #fee2e2; color: #b91c1c; }
  .none        { background: #f9fafb; color: #9ca3af; border: 1px solid #e5e7eb; }
  .not-submitted { text-align: center; padding: 4px; font-size: 7.5pt; font-weight: 700; background: #fef3c7; color: #b45309; border-radius: 4px; display: block; }

  .status-pill { display: inline-block; padding: 2px 8px; border-radius: 999px; font-size: 7pt; font-weight: 700; border: 1px solid #d1d5db; }
  .status-sent    { background: #dcfce7; color: #15803d; border-color: #bbf7d0; }
  .status-pending { background: #fef3c7; color: #b45309; border-color: #fde68a; }

  /* LEGEND */
  .legend { margin-top: 8px; font-size: 7.5pt; color: #6b7280; }
  .swatch { display: inline-block; width: 9px; height: 9px; border-radius: 2px; margin-right: 3px; vertical-align: middle; }

  /* FOOTER */
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 16px 0 10px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Shift Preferences</div>
        <div class="doc-subtitle">Manager Review</div>
        <div class="doc-ref">
          <strong>Week:</strong> {{ filters.week_start }} &ndash; {{ filters.week_end }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- STATUS PILLS -->
  <div class="pills-row">
    <span class="pill">{{ filters.department }}</span>
    <span class="pill">{{ filters.submission_status }}</span>
  </div>

  <!-- FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:16%" /><col style="width:17%" />
      <col style="width:16%" /><col style="width:17%" />
      <col style="width:16%" /><col style="width:17%" />
    </colgroup>
    <tr>
      <td class="info-key">Department</td><td class="info-val">{{ filters.department }}</td>
      <td class="info-key">Submission</td><td class="info-val">{{ filters.submission_status }}</td>
      <td class="info-key">Week</td><td class="info-val">{{ filters.week_start }} &ndash; {{ filters.week_end }}</td>
    </tr>
    {% if filters.search_text %}
    <tr>
      <td class="info-key">Search</td><td class="info-val" colspan="5">{{ filters.search_text }}</td>
    </tr>
    {% endif %}
  </table>

  <!-- STATS -->
  {% if stats %}
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Dept Staff</span><span class="s-value">{{ stats.departmentStaff or 0 }}</span></td>
      <td><span class="s-label">Submitted</span><span class="s-value">{{ stats.submittedPreferences or 0 }}</span></td>
      <td><span class="s-label">Unavailable</span><span class="s-value">{{ stats.unavailableRequests or 0 }}</span></td>
      <td><span class="s-label">Most Preferred</span><span class="s-value" style="font-size:9pt;">{{ stats.mostPreferredShift or '&mdash;' }}</span></td>
      <td><span class="s-label">Preference %</span><span class="s-value">{{ stats.mostPreferredPct or 0 }}%</span></td>
    </tr>
  </table>
  {% endif %}

  <!-- PREFERENCE TABLE -->
  <div class="section-title">Staff Preferences &mdash; {{ staff | length }} member(s)</div>
  {% if staff and staff | length %}
  <table class="pref-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="staff-col">Staff / Role</th>
        {% for day in days %}
        <th>{{ day.label }}<br>{{ day.dateLabel }}</th>
        {% endfor %}
        <th class="status-col">Status</th>
      </tr>
    </thead>
    <tbody>
      {% for member in staff %}
      <tr>
        <td class="staff-col">
          <div class="s-name">{{ member.name }}</div>
          <div class="s-role">{{ member.role }} &bull; {{ member.area }}</div>
        </td>
        {% if member.submitted %}
          {% for day in days %}
          {% set pref_label = member.shifts.get(day.date) if member.shifts else 'No Preference' %}
          {% set pref_label = pref_label or 'No Preference' %}
          {% set pl = pref_label | lower %}
          <td>
            <div class="pref-pill {% if 'unavailable' in pl %}unavailable{% elif 'morning' in pl %}morning{% elif 'afternoon' in pl or 'evening' in pl %}afternoon{% elif 'night' in pl %}night{% else %}none{% endif %}">
              {{ pref_label }}
            </div>
          </td>
          {% endfor %}
        {% else %}
          <td colspan="{{ days | length }}">
            <div class="not-submitted">Preference not submitted yet</div>
          </td>
        {% endif %}
        <td>
          <span class="status-pill {{ 'status-sent' if member.submitted else 'status-pending' }}">
            {{ 'Sent' if member.submitted else 'Pending' }}
          </span>
        </td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <div class="legend" style="margin-top:8px;font-size:7.5pt;color:#6b7280;">
    {% if shift_types %}
      {% for st in shift_types %}
        {% set sl = st | lower %}
        <span style="margin-right:10px;">
          <span class="swatch" style="display:inline-block;width:9px;height:9px;border-radius:2px;margin-right:3px;vertical-align:middle;
            background:{% if 'morning' in sl %}#dbeafe{% elif 'afternoon' in sl or 'evening' in sl %}#fef3c7{% elif 'night' in sl %}#e0e7ff{% else %}#f3f4f6{% endif %};
          "></span>{{ st }}
        </span>
      {% endfor %}
      <span style="margin-right:10px;"><span class="swatch" style="display:inline-block;width:9px;height:9px;border-radius:2px;margin-right:3px;vertical-align:middle;background:#fee2e2;"></span>Unavailable</span>
      <span style="margin-right:10px;"><span class="swatch" style="display:inline-block;width:9px;height:9px;border-radius:2px;margin-right:3px;vertical-align:middle;background:#f9fafb;border:1px solid #e5e7eb;"></span>No Preference</span>
    {% else %}
      <span style="color:#9ca3af;">No shift types configured in system.</span>
    {% endif %}
  </div>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No staff preferences found for the selected filters.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          Submitted preferences are guidance only &mdash; For internal use only
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
